22	  m: 'Material',
23	  i: 'Intelligence',
24	  n: 'Network',
25	  d: 'Diversity',
26	};
27	
28	/** ECharts theme object for dark site background. */
29	export const siteTheme = {
30	  backgroundColor: 'transparent',
31	  textStyle: {
32	    color: 'rgba(255, 255, 255, 0.85)',
33	    fontFamily: 'Satoshi, Inter, system-ui, sans-serif',
34	  },
35	};
36	
37	// -- Country data shape for chart functions --
38	export interface ChartCountry {
39	  name: string;
40	  m: number;
41	  i: number;
42	  n: number;
43	  d: number;
44	}
45	
46	// -- Dimension keys in canonical order --
47	const DIM_KEYS: DimensionKey[] = ['m', 'i', 'n', 'd'];
48	const DIM_LABELS = DIM_KEYS.map((k) => DIM_NAMES[k]);
49	
50	/** Fixed palette for multi-country comparison overlays. */
