67	      })),
68	      axisLine: { lineStyle: { color: 'rgba(255, 255, 255, 0.15)' } },
69	      splitLine: { lineStyle: { color: 'rgba(255, 255, 255, 0.1)' } },
70	      splitArea: { show: false },
71	    },
72	    series: [
73	      {
74	        type: 'radar',
75	        data: [
76	          {
77	            value: [country.m, country.i, country.n, country.d],
78	            name: country.name,
79	            areaStyle: { opacity: 0.25 },
80	            lineStyle: { width: 2 },
81	          },
82	        ],
83	      },
84	    ],
85	  };
86	}
87	
88	/** Generate ECharts comparison radar chart option for N overlapping countries. */
89	export function makeComparisonRadarOption(countries: ChartCountry[]): Record<string, unknown> {
90	  return {
91	    aria: { enabled: true },
92	    ...siteTheme,
93	    legend: {
94	      data: countries.map((c) => c.name),
95	      textStyle: { color: 'rgba(255,255,255,0.85)' },
96	    },
97	    radar: {
98	      shape: 'polygon',
